        var res = 0
        var i = index + 1
        while i > 0 {
            res += tree[i]
            i -= i & -i
        }
        return res
    }

    func rangeQuery(l: Int, r: Int) -> Int64 {
        return query(index: r) - query(index: l - 1)
    }
