func popcount(_ x: Int64) -> Int {
    var count = 0
    var num = x
    while num > 0 {
        count += num & 1
        num >>= 1
    }
    return count
}

func getDepth(x: Int64) -> Int {
    if x == 1 {
        return 0
    }
    var current = x
    var depth = 0
    while current != 1 {
        current = popcount(current)
        depth += 1
    }
    return depth
}

